{% capture 'meta_data' %}
{% for variant in product.variants %}
  {{ variant.id}}: '{{ variant.metafields.custom.notify_me_button_label | raw }}' {%- comment -%} Replace it with your NAMESPACE.KEY value {%- endcomment -%}
  {% unless forloop.last %},{% endunless %}
{% endfor %}
{% endcapture %}

<script>
  let metaData = { {{ meta_data }} };

  document.addEventListener("DOMContentLoaded", function() {
    var selector = document.querySelector('input[name=id]');
    var meta = document.querySelector('.product-form__alert.button.button--primary.button--fixed.w-full .btn-text');

    // Function to update metafield data
    function updateMetaField() {
      let variant_id = selector ? selector.value : null;
      if(variant_id && metaData[variant_id]) {
        meta.innerHTML = metaData[variant_id];
      } 
    }

    // Initial load for pre-selected variant
    updateMetaField();

    // Update on variant change
    if(selector) {
      selector.addEventListener('change', function() {
        updateMetaField();
      });
    }
  });
</script>

