{%- endcomment -%}
{% assign wholesale_tags = "Wholesale-Gold,Wholesale-Silver,Wholesale-Bronze,gold-dealer,silver-dealer,bronze-dealer" | split: "," %}
{% assign is_wholesale = false %}
{% if customer %}
  {% for tag in wholesale_tags %}
    {% if customer.tags contains tag %}
      {% assign is_wholesale = true %}
      {% break %}
    {% endif %}
  {% endfor %}
{% endif %}

{% if is_wholesale == false %}
<strong id="discount-message" style="color: #00adee;"></strong>
<script>
document.addEventListener("DOMContentLoaded", function () {
    function updateDiscountMessage() {
        let quantityInput = document.querySelector(".buy-buttons .quantity__input");
        let minusButton = document.querySelector(".buy-buttons button[name='minus']");
        let plusButton = document.querySelector(".buy-buttons button[name='plus']");
        let priceContainer = document.querySelector(".product__price");
        let priceElement = priceContainer ? priceContainer.querySelector(".price__regular") : null;
        let discountMessage = document.getElementById("discount-message");

        function isSoldOut() {
            let addToCartButton = document.querySelector(".product-form__submit .btn-text");
            return addToCartButton && addToCartButton.innerText.trim() === "Sold Out";
        }

        function getPrice() {
            if (!priceElement) return 0;
            let priceText = priceElement.textContent.trim().replace("$", "").replace(",", "");
            let price = parseFloat(priceText);
            return isNaN(price) ? 0 : price;
        }

        function calculateDiscount(qty) {
            if (isSoldOut()) {
                discountMessage.innerHTML = "";
                return;
            }

            let price = getPrice();
            if (price === 0) return;

            let save10Value = (price * 2 * 0.10).toFixed(2);
            let save20Value = (price * 3 * 0.20).toFixed(2);

            if (qty === 1) {
                discountMessage.innerHTML = `<strong style="color: #00adee;">BUY 2 SAVE 10% ($${save10Value}) AND BUY 3 SAVE 20% ($${save20Value})</strong>`;
            } else if (qty === 2) {
                discountMessage.innerHTML = `<strong style="color: #00adee;">BUY 3 SAVE 20% ($${save20Value})</strong>`;
            } else {
                discountMessage.innerHTML = "";
            }
        }

        function updateMessage() {
            let quantity = parseInt(quantityInput.value, 10);
            calculateDiscount(quantity);
        }

        function observePriceChanges() {
            if (!priceContainer) return;
            const observer = new MutationObserver(() => {
                priceElement = priceContainer.querySelector(".price__regular"); // Update reference
                updateMessage(); // Recalculate discount
            });

            observer.observe(priceContainer, { childList: true, subtree: true });
        }

        quantityInput.addEventListener("input", updateMessage);
        quantityInput.addEventListener("change", updateMessage);

        if (minusButton) minusButton.addEventListener("click", () => setTimeout(updateMessage, 50));
        if (plusButton) plusButton.addEventListener("click", () => setTimeout(updateMessage, 50));

        observePriceChanges(); // Watch for price updates
        updateMessage(); // Initial discount calculation
    }

    updateDiscountMessage();
});
</script>
{% endif %}
